import psycopg2
from psycopg2 import errorcodes
import getpass
import sys

def main():
    host = input("Enter database hostname or IP address: ")
    db_name = input("Enter database name: ")
    user = input("Enter database username: ")
    password = getpass.getpass("Enter database password: ")

    try:
        conn = psycopg2.connect(host=host, database=db_name, user=user, password=password)
        cur = conn.cursor()
        
        while True:
            print("\nAvailable extensions:")
            for i in range(1, 100):
                try:
                    cur.execute(f"SELECT name FROM pg_available_extensions WHERE installed_version IS NULL LIMIT 1 OFFSET {i}")
                    result = cur.fetchone()
                    if result:
                        print(result[0])
                except psycopg2.ProgrammingError as e:
                    print(e)
            extension_name = input("\nEnter the number of your chosen extension or 'q' to quit: ")

            if extension_name.lower() == 'q':
                break

            try:
                cur.execute(f"CREATE EXTENSION {extension_name}")
                conn.commit()
                print(f"Extension '{extension_name}' created successfully.")
            except psycopg2.errors.UniqueViolation as e:
                print(f"'{extension_name}' is already installed.")

        # Enable extensions like plpythonu for advanced database functionality
        while True:
            print("\nAvailable extensions:")
            for i in range(1, 100):
                try:
                    cur.execute(f"SELECT name FROM pg_available_extensions WHERE name IN ('plpythonu', 'plperl', 'pltcl') LIMIT 1 OFFSET {i}")
                    result = cur.fetchone()
                    if result:
                        print(result[0])
                except psycopg2.ProgrammingError as e:
                    print(e)
            extension_name = input("\nEnter the number of your chosen extension or 'q' to quit: ")

            if extension_name.lower() == 'q':
                break

            try:
                cur.execute(f"CREATE OR REPLACE FUNCTION {extension_name}()")
                conn.commit()
                print(f"Extension '{extension_name}' enabled successfully.")
            except psycopg2.errors.UniqueViolation as e:
                print(f"'{extension_name}' is already enabled.")

    except psycopg2.Error as e:
        print(f"An error occurred: {e}")

if __name__ == "__main__":
    main()